import type { SearchInputConfig } from '@linm-soft-org/linm-web-common-components';
import { createStaticLookupSearchConfig } from '../../../../../components/search';
import type { PaymentChannelInitItem, PostingReasonInitItem } from '../../../../../services/voucherInit/endpoint';

export function dedupePostingReasonRules(rules: PostingReasonInitItem[]): PostingReasonInitItem[] {
  const seen = new Set<string>();
  return rules.filter(r => {
    const key = r.code.trim().toLowerCase();
    if (!key || seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

export function createPostingReasonSearchConfig(
  rules: PostingReasonInitItem[],
): SearchInputConfig<PostingReasonInitItem> {
  return createStaticLookupSearchConfig({
    loadItems: () => dedupePostingReasonRules(rules),
    getKey: r => r.code,
    getCode: r => r.code,
    getName: r => r.name,
    getFilterText: r => `${r.code} ${r.name}`,
    codeHeaderLabel: 'Mã',
    nameHeaderLabel: 'Lý do / Định khoản',
  });
}

export function createPaymentChannelSearchConfig(
  channels: PaymentChannelInitItem[],
): SearchInputConfig<PaymentChannelInitItem> {
  return createStaticLookupSearchConfig({
    loadItems: () => channels,
    getKey: ch => ch.code,
    getCode: ch => ch.code,
    getName: ch => ch.name,
    getFilterText: ch => `${ch.code} ${ch.name}`,
    codeHeaderLabel: 'Mã',
    nameHeaderLabel: 'Hình thức thanh toán',
  });
}
