/** Cross-MFE: HĐ bán → Tạo phiếu thu (`/kt/pt/them`). */

export const RECEIPT_PREFILL_FROM_INVOICE_KEY = 'receiptPrefillFromInvoice';

export type ReceiptPrefillFromInvoice = {
  customerId: string;
  customerCode?: string;
  customerName?: string;
  invoiceId: string;
  invoiceCode: string;
  amount: number;
  receiptKind: '2';
  description?: string;
};

const CROSS_MFE_STATE_KEY = 'linm_cross_mfe_nav_state';

export function consumeReceiptPrefillFromInvoice(): ReceiptPrefillFromInvoice | null {
  try {
    const raw = sessionStorage.getItem(CROSS_MFE_STATE_KEY);
    if (raw) {
      const parsed = JSON.parse(raw) as {
        path?: string;
        state?: Record<string, ReceiptPrefillFromInvoice>;
      };
      if (parsed.path === '/kt/pt/them' && parsed.state?.[RECEIPT_PREFILL_FROM_INVOICE_KEY]) {
        sessionStorage.removeItem(CROSS_MFE_STATE_KEY);
        return parsed.state[RECEIPT_PREFILL_FROM_INVOICE_KEY];
      }
    }
  } catch {
    /* ignore */
  }
  return null;
}
